  },
  "application": {
    "methods": [
      "Contact NH Department of Health and Human Services (DHHS) or case management agency (e.g., Community Partners: (603) 516-9300, 25 Old Dover Road, Rochester, NH 03867)[3]",
      "No specific online URL, form name, mail address, or in-person offices listed in sources; eligibility determined by DHHS after financial and medical criteria met[3]"
    ],
    "processing_time": "Not specified in sources",
    "waitlist": "Not specified in sources",
    "forms": ["Medical Eligibility Assessment (MEA) instrument for functional need[1]"],
    "documents": ["Proof of income, assets/home equity, residency, disability (if under 65), medical/functional need evidence for NFLOC assessment (not explicitly listed; inferred from criteria)[1]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; New Hampshire residents[1]",
    "regional_variations": "Case management agencies assigned statewide (e.g., Community Partners in Rochester area); potential provider differences but program uniform[3]",
    "offices_or_providers": ["Community Partners, 25 Old Dover Road, Rochester, NH 03867 (example)[3]"]
  },
  "official_source": "https://www.dhhs.nh.gov (inferred from program admin; see also Medicaid.gov waiver: https://www.medicaid.gov/medicaid/section-1115-demo/demonstration-and-waiver-list/82541)[2]",
